import{_ as e,o as a,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"凛冬之女","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/3.心智类/凛冬之女.md","filePath":"4.资源分区/1.血统与训练/3.心智类/凛冬之女.md"}'),s={name:"4.资源分区/1.血统与训练/3.心智类/凛冬之女.md"};function o(d,b,l,_,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"凛冬之女",tabindex:"-1"},[p("凛冬之女 "),r("a",{class:"header-anchor",href:"#凛冬之女","aria-label":'Permalink to "凛冬之女"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风025春节版")])])],-1),n('<h1 id="凛冬之女-1" tabindex="-1">凛冬之女 <a class="header-anchor" href="#凛冬之女-1" aria-label="Permalink to &quot;凛冬之女&quot;">​</a></h1><p>凛冬之女<br> 血统<br> 前提：女性，拥有魔力能量池<br> 描述：冬季，带给世间死寂与宁静，也是孕育新春的序章。凛冬之女是冷冬的女儿，寒霜的化身，她的长发如细碎的冰凌，流淌着月光的冷辉；她周身缭绕着丝丝白雾，那是北风与寒气的拥簇。凛冬之女的出生伴随着一场暴风雪，刺骨寒冷将护佑她成长，并逐步掌握冷冬母亲的力量。在各族混战鲜血遍地的大陆上，凛冬之女运用自己的力量传播信仰与和平，为枯寂赋予美丽，为绝望涂上纯白是她的使命，在毁灭重孕育新生，在严寒中酝酿希望。</p><p>D级：幼冬之芽<br> 描述：凛冬的血脉初步苏醒，如萌生的幼芽般脆弱。<br> 【冬芽】身体开始发生变化，发色变为冰晶般的银蓝色，身体常温变为0度，且会对周身不断散发白丝状冷气(如小空调一般)，但自身肉体不会因这种寒冷而感到不适，反而在寒冷的淬炼下得到升华。你获得2点天生防御，以及基于天生防御的【防能量】和【防弹】，并且无需饮食。<br> 【暖阳】跳动的心脏是全身上下唯一具有生的活力的部位，魔力随着冰冷的血液输送至全身每一处，初步显露出对魔力和魔法的亲和与掌握，你在释放核心派系法术时获得1点能量加值。</p><p>C级：霜华初凝<br> 描述：凛冬的血脉蔓延全身，肉体彻底转变为永不融化的寒冰，但外形仍保持人类。<br> 【凛冬之体】身体变为了永冰，这不会带来外表的改变，丝丝寒气笼罩在皮肤外侧形成一层额外保护，足以应对任何方式的攻击。你的生命值被转化为结构值，获得基于天生防御的【适应】,获得1点快速维修（12医疗池）<br> 【初冬】对体内魔力的掌控进一步熟练，释放的瞬间犹如置身寒冬。每当一场影片结束时，若你参加过至少一场同级别战斗，则在释放核心派系法术时获得1点法强，从第四场开始，改为获得2点法强，一共可以成长5次</p><p>B级：冰域之主<br> 描述：与冷冬母亲的联系继续深化，冰雪与寒风将追随每一步足迹。<br> 【凛冬之体】除去散发的寒气，现在周身数米内还会不定时地吹起寒风和飘落雪花以营造尽可能适宜的环境，但对本身力量的掌控足以主动收敛。在上一等级的基础上，你获得5点天生防御，以及自适应长休。<br> 【冬至】寒霜之力犹如在掌心间跳动的精灵，你的施法攻击获得【法破】特性，你在释放核心派系法术时获得8加骰，以及施法主属性附加*1点附加成功。</p><p>-----<br> 技能树<br> 注：本血统下技能树即使没有购买血统也可正常购买，前提是本身具有某种与冰雪相关的能力，或是信仰寒冬女神。</p><p>冰爆<br> 类型：攻击技<br> 等级：D<br> 派系：核心<br> 花费：2<br> 成分：动作、语言<br> 动作：标准<br> 射程：15米直线<br> 目标：范围内全部敌人<br> 持续：立即<br> 瞬间降温并引爆空气中被聚集的魔力，施法后遗留的无数冰棱可以做为冷饮甜品的原材料。此次攻击造成冻寒伤害，并获得1点施法鉴定上的附加成功。</p><p>研发10xp：<br> 暴风雪<br> 类型：攻击技<br> 等级：C<br> 派系：核心<br> 花费：6<br> 成分：姿态，言语<br> 动作：标准<br> 射程：50米扇形<br> 目标：范围内全部敌人<br> 持续：立即<br> 刺骨的寒风以施法者为起点呼啸而出，卷起漫天雪花，迅速覆盖大地。雪花在半空中旋转拉扯，凝结成无数锋利的冰刃在暴风中疾驰，犹如怒吼的野兽发出凛冽的破空声。射程提升35米，范围提升为扇形。</p><p>研发20xp：<br> 霜星陨落<br> 类型：攻击技<br> 等级：B<br> 派系：核心<br> 花费：9<br> 成分：姿态，言语<br> 动作：标准<br> 射程：75米圆形<br> 目标：范围内全部敌人<br> 持续：立即<br> 天空中浮现出一个巨大的冰蓝漩涡，仿佛是另一片宇宙的门户被打开。漩涡深处，一颗散发着寒冷光芒的小型陨星缓缓显现，拉出一道寒光闪耀的冰晶尾焰，夹杂着漫天繁星般无数细小的冰晶坠向大地，掀起一场冰晶风暴。射程提升25米，范围提升为圆形，附带伤害等额冰冻点数。</p><p>涟漪涌动<br> D+500<br> 类型：增强技<br> 等级：D<br> 派系：无<br> 花费：2<br> 成分：动作、语言<br> 动作：移动<br> 射程：自身<br> 目标：单体<br> 持续：一轮<br> 通过将魔力提前散播的方式，使魔法的威力能更迅速和完整地扩散。使用涟漪涌动后的一轮内，下一道类型为攻击技的法术射程增加30米，并获得5点【高速】。</p><p>---<br> 下属物品</p><p>武器<br> 永冻权柄(一阶)<br> D+500<br> 魔幻本质<br> 永冻权柄是一支约与成年人身高相当的细长法杖，由一种近乎透明的冰晶状物质铸造而成，杖身表面刻满了古老的冰霜符文。杖顶镶嵌着名为“永冻之核”的纯净冰晶，这也是这支法杖的力量来源，核心周围围绕着冰刺状的荆棘雕刻。永冻权柄传说为冰霜巨人族（Jotunn）首领的象征物，在远古的冰河纪，巨人们以这件法杖维持北境的寒冷，守护着极寒之地不被炎热入侵，同时也被认为是寒冬女神作为恩赐授予信徒的神器。无论如何，这支法杖在岁月流逝和多次重铸后已经失去了大部分力量。<br> 这支法杖具有3点法术强度。<br> 【北境之魂】法杖上仍附着冰霜巨人的微弱气息，在北境的漫漫长夜中，永冻之核指明巨人们前进的道路。持有者获得黑暗视觉，免疫C级困难地形。<br> 【永冻之核】这颗永不融化的冰晶仍在提供源源不断的魔力，持有者的魔力上限提升6。</p><p>永冻权柄(二阶)<br> C+1000<br> 在此阶段，永冻之核的力量部分回归，杖身表面的符文开始散发微弱的蓝白光芒。<br> 这支法杖现在具有11点法术强度。<br> 【冰霜符文】做为激活永冻之核过程的一部分，这些古老的符文也具有相当恐怖的力量。持有者的施法鉴定获得2点能量加值，以及2点附加成功。<br> 【永冻之核】在上一等级的基础上，每小时一次，持有者进行一次魔力池关键属性检定，恢复成功数点魔力，这会计入每日的恢复上限</p><p>永冻权柄(三阶)<br> B+2000<br> 在此阶段，永冻之核已恢复活力，将脱离杖身的束缚，以自身魔力以漂浮姿态与杖身连接。<br> 这支法杖现在具有26点法术强度。<br> 【审判】永冻权柄将代为审判寒冬的敌人，持有者的施法攻击造成冻寒伤害，获得【碾压】特性与5点【威猛】。每轮一次，持有者可以将攻击鉴定重掷一次，无论结果如何，必须接受。<br> 【永冻之核】苏醒后的永冻之核将展现它真正的力量，在上一等级的基础上，一场景一次，消耗9点魔力，以一个移动动作激活核心，持有者本场景内的施法攻击范围将被冰棱与风雪覆盖，这视为施加持续一个场景的A级困难地形。</p><p>奇物<br> 霜华的轻纱<br> C+1000<br> 魔幻本质<br> 占据斗篷位<br> 一件纯白色斗篷，穿戴后身体犹如雪花般轻盈。斗篷在魔力附着下变得格外坚韧，战斗中会紧贴佩戴者如同融为一体，无论是来自利器还是钝器的攻击都会被卸力，为佩戴者提供全面保护。<br> 效果：佩戴者获得普通飞行能力，2点天生防御，额外获得血统等级*1点DR/-，基于天生防御。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',17)])])}const m=e(s,[["render",o]]);export{f as __pageData,m as default};
